/**
 * Per-country narrative prose for the report pages.
 *
 * GENERATED by a Sonnet agent workflow grounded ONLY in each country's sourced
 * facts (FATF status, sanctions, WGI governance domains, CPI, composite score,
 * enforcement summary) - no invented figures or dates. Committed as static
 * content so the pages stay prerender-safe and SEO-rich with no runtime AI cost.
 * Re-run the workflow (scripts/build-country-facts.ts + the narrative agents) to
 * refresh. Do not edit by hand.
 */

export interface CountryNarrative {
  /** One-line summary for the report hero. */
  summary: string;
  /** 3-4 bullets: why this country matters for financial-crime risk. */
  whyItMatters: string[];
  /** A grounded analysis paragraph. */
  analysis: string;
  /** A forward-looking outlook paragraph. */
  outlook: string;
  /** 3-4 key watchpoints for firms. */
  keyWatchpoints: string[];
}

